// src/features/tasks/taskService.js
import { db } from '../../core/database.js';

export async function createTask(data, options = {}) {
  const { notify = true, validate = true, dryRun = false } = options;

  if (validate) {
    validateTask(data);
  }

  if (dryRun) {
    return { ...data, id: 'dry-run', createdAt: new Date() };
  }

  const task = await db.tasks.insert(data);

  if (notify) {
    await notifyTaskCreated(task);
  }

  return task;
}

function validateTask(data) {
  if (!data.title) throw new Error('Title is required');
  if (data.title.length > 200) throw new Error('Title too long');
}

async function notifyTaskCreated(task) {
  // placeholder for future notification system
  console.log(`Task ${task.id} created`);
}
